export type QuoteDetails = NonNullable<paths['/quote/v2']['post']['responses']['200']['content']['application/json']['details']>;
export type QuoteStepId = NonNullable<paths['/quote/v2']['post']['responses']['200']['content']['application/json']['steps']>['0']['id'];
export type TransactionStepState = 'confirming' | 'validating' | 'complete';
export type SignatureStepState = 'signing' | 'posting' | 'validating' | 'complete';
export type Execute = {
    errors?: {
        message?: string;
        orderId?: string;
    }[];
    fees?: CallFees;
    breakdown?: CallBreakdown;
    details?: QuoteDetails;
    error?: any;
    refunded?: boolean;
    steps: {
        error?: string;
        errorData?: any;
        action: string;
        description: string;
        kind: 'transaction' | 'signature';
        id: QuoteStepId;
        requestId?: string;
        depositAddress?: string;
        items: {
            status: 'complete' | 'incomplete';
            receipt?: TransactionReceipt | SvmReceipt | SuiReceipt | TronReceipt;
            checkStatus?: 'refund' | 'waiting' | 'failure' | 'pending' | 'submitted' | 'success' | 'unknown';
            progressState?: TransactionStepState | SignatureStepState;
            data?: any;
            check?: CheckApi;
            orderIndexes?: number[];
            orderIds?: string[];
            error?: string;
            txHashes?: {
                txHash: string;
                chainId: number;
                isBatchTx?: boolean;
            }[];
            internalTxHashes?: {
                txHash: string;
                chainId: number;
                isBatchTx?: boolean;
            }[];
            errorData?: any;
            orderData?: {
                crossPostingOrderId?: string;
                orderId: string;
                orderIndex: string;
            }[];
            isValidatingSignature?: boolean;
        }[];
    }[];
    request?: AxiosRequestConfig;

